UPDATE `object_validations` SET `trigger_code` = 'from orionbase.common import models\nfrom decimal import Decimal\nfrom django.db.models import Q, Sum, F, FloatField\nimport logging\nlogger = logging.getLogger(\'orion.sales_data_management\')\n\nif instance and instance.state.name == \'sent_approval\':\n    # 会议类型\n    event_record_type = models.ObjectRecordTypes.objects.get(id=instance.record_type_id)\n    a_tier = {u\'北京\', u\'上海\', u\'广州\', u\'北京市\', u\'上海市\', u\'广州市\'}\n    notification_msg = \'\'\n    git_expense_record_type = [\'cs_training_fee\']\n    event_expense_reord_type = [\'hotel_fee\', \'meal_fee\', \'communication_expense\',\n                                \'cs_other\', \'cs_rent_facility\', \'cs_rent_expense\', \'cs_three_expense\']\n\n    event_expense = models.EventExpenses.objects.filter(event_id=instance.id,\n                                                        record_type__name__in=event_expense_reord_type,\n                                                        deleted=0,\n                                                        total_expense__isnull=False).values_list(\n        \'record_type__name\', \'record_type__label\', \'total_expense\', \'number_1\', \'number_2\')\n\n    class ExpenseChecker(object):\n        error_msg = u\'费用信息填写有误，请检查\'\n\n        @classmethod\n        def _check_count(cls, num):\n            # if num is None:\n            #     return False\n            if int(num) <= 0:\n                return False\n            return True\n\n        @classmethod\n        def _avg(cls, divisor, dividend):\n            return round(Decimal(divisor) / Decimal(dividend))\n\n        @classmethod\n        def _check_limit(cls, price, limit, msg):\n            if price > limit:\n                msg += u\'人均费用{}元，超越上限{}元\'.format(price,limit)\n            return msg\n\n        @classmethod\n        def add_msg(cls, msg, expense, count, limit):\n            if cls._check_count(count):\n                avg_expense = cls._avg(expense, count)\n                msg = cls._check_limit(avg_expense, limit, msg)\n            else:\n                msg = cls.error_msg\n            return msg\n\n    city = models.Events.advance_objects.filter(geography_id=instance.geography).values_list(\'geography__city\',\n                                                                                             flat=True)\n    city = city[0] if city else None\n    # 城市会\n    if event_record_type.id in (\'d9536480-5eed-11e6-8920-5cc5d4d378cb\',\'a2ae2ac5-c93a-4fcf-8834-e3592fe4ad48\'):\n        for event_expense_record_type_name, event_expense_record_type_label, \\\n            total_expense, number_1, number_2 in event_expense:\n            person_price = round(Decimal(total_expense) / Decimal(number_1), 2)\n            if event_expense_record_type_name in (\'meal_fee\'):\n                if event_record_type.id in (\'05320400-e35f-11e9-b9aa-0298a739dec0\'):\n                    if number_2 < 0:\n                        notification_msg = u\'餐费填写有误\'\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                    elif number_2 > 200:\n                        notification_msg = u\'餐费人均费用{}元，超越上限300元\'.format(number_2)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                elif event_record_type.id in (\'21f2482f-e35f-11e9-b9aa-0298a739dec0\'):\n                    if int(total_expense) <= 0:\n                        notification_msg = u\'餐费填写有误\'\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                    else:\n                        if person_price > 200:\n                            notification_msg = u\'餐费人均费用{}元，超越上限300元\'.format(person_price)\n                            raise create_validation_trigger_rule_errors(notification_msg)\n            elif event_expense_record_type_name in (\'hotel_fee\'):\n                if city in a_tier:\n                    if person_price > 1500:\n                        notification_msg = u\'住宿费人均费用{}元，超越上限1500元\'.format(person_price)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                else:\n                    if person_price > 1200:\n                        notification_msg = u\'住宿费人均费用{}元，超越上限1200元\'.format(person_price)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n    # 科室会\n    elif event_record_type.id in (\'05320400-e35f-11e9-b9aa-0298a739dec0\', \'21f2482f-e35f-11e9-b9aa-0298a739dec0\'):\n        for event_expense_record_type_name, event_expense_record_type_label, \\\n            total_expense, number_1, number_2 in event_expense:\n            if event_expense_record_type_name in (\'meal_fee\'):\n                if event_record_type.id in (\'05320400-e35f-11e9-b9aa-0298a739dec0\'):\n                    if number_2 < 0:\n                        notification_msg = u\'餐费填写有误\'\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                    elif number_2 > 200:\n                        notification_msg = u\'餐费人均费用{}元，超越上限200元\'.format(number_2)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                elif event_record_type.id in (\'21f2482f-e35f-11e9-b9aa-0298a739dec0\'):\n                    if int(total_expense) <= 0:\n                        notification_msg = u\'餐费填写有误\'\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                    else:\n                        person_price = round(Decimal(total_expense) / Decimal(number_1),2)\n                        if person_price > 200:\n                            notification_msg = u\'餐费人均费用{}元，超越上限200元\'.format(person_price)\n                            raise create_validation_trigger_rule_errors(notification_msg)\n\n    # 市场部会议\n    elif event_record_type.id in (\'bdf5191c-efe8-11e9-b9aa-0298a739dec0\', \'05b19885-efe9-11e9-b9aa-0298a739dec0\'):\n        for event_expense_record_type_name, event_expense_record_type_label, \\\n            total_expense, number_1, number_2 in event_expense:\n            person_price = round(Decimal(total_expense) / Decimal(number_1), 2)\n            if event_expense_record_type_name in (\'hotel_fee\'):\n                if city in a_tier:\n                    if person_price > 1500:\n                        notification_msg = u\'住宿费人均费用{}元，超越上限1500元\'.format(person_price)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                else:\n                    if person_price > 1200:\n                        notification_msg = u\'住宿费人均费用{}元，超越上限1200元\'.format(person_price)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n            elif event_expense_record_type_name in (\'meal_fee\'):\n                if instance.picklist_1 == \'0531e159-1e4d-44f5-8970-fffc0f1e5597\':\n                    if person_price > 100:\n                        notification_msg = u\'餐费人均费用{}元，超越上限100元\'.format(person_price)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n                else:\n                    if person_price > 500:\n                        notification_msg = u\'餐费人均费用{}元，超越上限500元\'.format(person_price)\n                        raise create_validation_trigger_rule_errors(notification_msg)\n    # 病人教育会\n    elif event_record_type in (\'cffbdab8-101f-4775-96b7-3fa8baccd035\', \'cffbdab8-101f-4775-96b7-3fa8baccd036\'):\n        total_expense = sum(instance.eventexpenses_set.filter(\n            deleted=0, total_expense__isnull=False).values_list(\'total_expense\', flat=True))\n        if total_expense <= 500:\n            notification_msg = u\'杂费和餐费低于500元\'\n            raise create_validation_trigger_rule_errors(notification_msg)\n        for event_expense_record_type_name, event_expense_record_type_label, \\\n            total_expense, number_1, number_2 in event_expense:\n            if event_expense_record_type_name in (\'cs_other\'):\n                if total_expense > 500:\n                    notification_msg = u\'杂费超越上限500元\'\n                    raise create_validation_trigger_rule_errors(notification_msg)' WHERE (`id` = '3ab786ab-e144-11ea-bc49-0215c63fce1a');

